<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Banner;use Illuminate\Http\Request;class BannerController extends Controller{public function index(){$banners=Banner::latest()->paginate(15);return view('admin.banners.index',compact('banners'));}public function create(){return view('admin.banners.form',['banner'=>new Banner]);}public function store(Request $r){Banner::create($this->data($r));return redirect()->route('admin.banners.index')->with('success','Banner saved.');}public function edit(Banner $banner){return view('admin.banners.form',compact('banner'));}public function update(Request $r,Banner $banner){$banner->update($this->data($r));return redirect()->route('admin.banners.index')->with('success','Banner updated.');}private function data(Request $r){$d=$r->validate(['title'=>'required|max:191','subtitle'=>'nullable','image'=>'nullable|max:191','mobile_image'=>'nullable|max:191','button_text'=>'nullable|max:100','button_url'=>'nullable|max:191','placement'=>'required|max:50','sort_order'=>'nullable|integer']);$d['is_active']=$r->boolean('is_active');return $d;}}
